diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 0620752e32139..f31261abb812c 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -2220,10 +2220,12 @@ Instruction *InstCombinerImpl::visitAnd(BinaryOperator &I) {
   Value *Op0 = I.getOperand(0), *Op1 = I.getOperand(1);

   Value *X, *Y;
-  if (match(Op0, m_OneUse(m_LogicalShift(m_One(), m_Value(X)))) &&
+  const APInt *C;
+  if ((match(Op0, m_OneUse(m_LogicalShift(m_One(), m_Value(X)))) ||
+       (match(Op0, m_OneUse(m_Shl(m_APInt(C), m_Value(X)))) && (*C)[0])) &&
       match(Op1, m_One())) {
-    // (1 << X) & 1 --> zext(X == 0)
     // (1 >> X) & 1 --> zext(X == 0)
+    // (C << X) & 1 --> zext(X == 0), when C is odd
     Value *IsZero = Builder.CreateICmpEQ(X, ConstantInt::get(Ty, 0));
     return new ZExtInst(IsZero, Ty);
   }
@@ -2246,7 +2248,6 @@ Instruction *InstCombinerImpl::visitAnd(BinaryOperator &I) {
       isKnownToBeAPowerOfTwo(Y, /*OrZero*/ true, /*Depth*/ 0, &I))
     return BinaryOperator::CreateAnd(Builder.CreateNot(X), Y);

-  const APInt *C;
   if (match(Op1, m_APInt(C))) {
     const APInt *XorC;
     if (match(Op0, m_OneUse(m_Xor(m_Value(X), m_APInt(XorC))))) {

tests.test_body:
define i32 @test1(i32 %A) {
; CHECK-LABEL: @test1(
; CHECK-NEXT:    ret i32 0
  %B = and i32 %A, 0
  ret i32 %B
}

tests.source_program:
define i32 @test1(i32 %A) {
  %B = and i32 %A, 0
  ret i32 %B
}

define <2 x i32> @test_vec(<2 x i32> %x) {
  %shl = shl <2 x i32> <i32 5, i32 5>, %x
  %and = and <2 x i32> %shl, <i32 1, i32 1>
  ret <2 x i32> %and
}

define i32 @test_with_1(i32 %x) {
  %shl = shl i32 1, %x
  %and = and i32 %shl, 1
  ret i32 %and
}

define i32 @test_with_3(i32 %x) {
  %shl = shl i32 3, %x
  %and = and i32 %shl, 1
  ret i32 %and
}

define i32 @test_with_5(i32 %x) {
  %shl = shl i32 5, %x
  %and = and i32 %shl, 1
  ret i32 %and
}

define i32 @test_with_even(i32 %x) {
  %shl = shl i32 4, %x
  %and = and i32 %shl, 1
  ret i32 %and
}

define i32 @test_with_neg_5(i32 %x) {
  %shl = shl i32 -5, %x
  %and = and i32 %shl, 1
  ret i32 %and
}

define i32 @test_with_neg_even(i32 %x) {
  %shl = shl i32 -4, %x
  %and = and i32 %shl, 1
  ret i32 %and
}
